	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FDateTime*)FMemory::Malloc(sizeof(FDateTime), alignof(FDateTime));
	NePyBase::EnsureCopyToStructSafely<FDateTime>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
